To encapsulate the functionality for arbitrarily large integers within a class, we'll create a `BigInt` class. This class will allow us to represent large numbers as a vector of integers, with each integer in the vector representing a single digit as requested. Here's a sample implementation of the `BigInt` class with an addition method:

```cpp
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

class BigInt {
private:
    std::vector<int> digits; // The number is stored in reverse order

public:
    // BigInt can be constructed from a string
    BigInt(const std::string& number) {
        for (int i = number.length() - 1; i >= 0; --i) {
            digits.push_back(number[i] - '0');
        }
    }

    // Addition of two BigInts
    BigInt operator+(const BigInt& other) const {
        std::vector<int> result;
        const std::vector<int>& longer = digits.size() > other.digits.size() ? digits : other.digits;
        const std::vector<int>& shorter = digits.size() > other.digits.size() ? other.digits : digits;

        int carry = 0;
        for (size_t i = 0; i < longer.size(); ++i) {
            int sum = longer[i] + (i < shorter.size() ? shorter[i] : 0) + carry;
            result.push_back(sum % 10);
            carry = sum / 10;
        }
        if (carry) {
            result.push_back(carry);
        }
        return BigInt(result);
    }

    // Getter for digits (for external use such as printing)
    const std::vector<int>& getDigits() const {
        return digits;
    }

private:
    // Private constructor that constructs a BigInt from a vector of digits
    BigInt(const std::vector<int>& digitsVector) : digits(digitsVector) {}

    friend std::ostream& operator<<(std::ostream& os, const BigInt& bigint);
};

// Overload << operator to print a BigInt
std::ostream& operator<<(std::ostream& os, const BigInt& bigint) {
    for (auto it = bigint.digits.rbegin(); it != bigint.digits.rend(); ++it) {
        os << *it;
    }
    return os;
}

int main() {
    std::string num1, num2;
    std::cout << "Enter the first number: ";
    std::cin >> num1;
    std::cout << "Enter the second number: ";
    std::cin >> num2;

    BigInt bigInt1(num1);
    BigInt bigInt2(num2);
    BigInt result = bigInt1 + bigInt2;

    std::cout << "Sum: " << result << std::endl;

    return 0;
}
```

