void BigInt::add(BigInt b) {
    unsigned int maxsize = std::max(num.size(), b.num.size());

    // First, resize the num vector to the required size and initialize new elements to 0.
    num.resize(maxsize, 0);

    int carry = 0;
    for (unsigned int i = 0; i < maxsize || carry > 0; i++) {
        int aValue = (i < num.size()) ? num[i] : 0; // Safe access, since we resized above.
        int bValue = (i < b.num.size()) ? b.num[i] : 0; // Safe access, since we check the bounds.

        int sum = aValue + bValue + carry; // Calculate the new sum

        num[i] = sum % 10;              // Store the single digit
        carry = sum / 10;                // Calculate the new carry

        if (i >= num.size() - 1 && carry > 0) {
            num.push_back(carry);        // If there's a carry on the last iteration, push it to the end of the vector.
            carry = 0;                   // Reset carry (important to end the loop).
        }
